283	// Fetch registries with new schema (array of objects with name, homepage, url, featured).
284	export async function getRegistries(options?: { useCache?: boolean }) {
285	  options = {
286	    useCache: true,
287	    ...options,
288	  }
289	
290	  const url = `${REGISTRY_URL}/registries.json`
291	  const [data] = await fetchRegistry([url], {
292	    useCache: options.useCache,
293	  })
294	
295	  try {
296	    return registriesSchema.parse(data)
297	  } catch (error) {
298	    if (error instanceof z.ZodError) {
299	      throw new RegistriesIndexParseError(error)
300	    }
301	
302	    throw error
303	  }
304	}
