"use client"

import * as React from "react"
import { Check } from "lucide-react"

import { cn } from "@/lib/utils"

type StepperProps = {
  activeStep?: number
  defaultValue?: number
  onStepChange?: (step: number) => void
  orientation?: "horizontal" | "vertical"
  linear?: boolean
}

type StepperContextProps = {
  activeStep: number
  orientation: "horizontal" | "vertical"
  linear: boolean
  goToStep: (step: number) => void
}

type StepItemContextProps = {
  step: number
  state: "completed" | "active" | "upcoming"
  disabled: boolean
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)

  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }

  return context
}

const StepItemContext = React.createContext<StepItemContextProps | null>(null)

function useStepItem() {
  const context = React.useContext(StepItemContext)

  if (!context) {
    throw new Error("useStepItem must be used within a <StepperItem />")
  }

  return context
}

function Stepper({
  activeStep: activeStepProp,
  defaultValue = 0,
  onStepChange,
  orientation = "horizontal",
  linear = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  const [internalStep, setInternalStep] = React.useState(defaultValue)
  const activeStep = activeStepProp ?? internalStep

  const goToStep = React.useCallback(
    (step: number) => {
      if (linear && step > activeStep + 1) return
      onStepChange?.(step)
      if (activeStepProp === undefined) {
        setInternalStep(step)
      }
    },
    [activeStep, activeStepProp, linear, onStepChange]
  )

  return (
    <StepperContext.Provider
      value={{
        activeStep,
        orientation,
        linear,
        goToStep,
      }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("flex flex-col gap-4", className)}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  disabled: disabledProp,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
  disabled?: boolean
}) {
  const { activeStep, orientation, linear } = useStepper()

  const state =
    step < activeStep
      ? "completed"
      : step === activeStep
        ? "active"
        : "upcoming"

  const disabled = disabledProp ?? (linear && step > activeStep + 1)

  return (
    <StepItemContext.Provider value={{ step, state, disabled }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        className={cn(
          "group/step-item flex items-center gap-2",
          orientation === "vertical" && "items-start",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { goToStep } = useStepper()
  const { step, state, disabled } = useStepItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      aria-current={state === "active" ? "step" : undefined}
      disabled={disabled}
      onClick={() => goToStep(step)}
      className={cn(
        "inline-flex size-9 shrink-0 items-center justify-center rounded-full border text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
        state === "completed" &&
          "border-primary bg-primary text-primary-foreground",
        state === "active" && "border-2 border-primary text-primary",
        state === "upcoming" &&
          "border-muted-foreground/25 text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? (state === "completed" ? <Check className="size-4" /> : step + 1)}
    </button>
  )
}

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { state } = useStepItem()

  return (
    <div
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium",
        state === "upcoming" && "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { state } = useStepItem()

  return (
    <div
      data-slot="stepper-description"
      data-state={state}
      className={cn(
        "text-xs text-muted-foreground",
        state === "upcoming" && "text-muted-foreground/60",
        className
      )}
      {...props}
    />
  )
}

function StepperSeparator({
  step: stepProp,
  className,
  ...props
}: React.ComponentProps<"div"> & { step?: number }) {
  const { activeStep, orientation } = useStepper()

  const state =
    stepProp !== undefined && stepProp < activeStep ? "completed" : "upcoming"

  return (
    <div
      data-slot="stepper-separator"
      data-state={state}
      className={cn(
        "bg-border transition-colors data-[state=completed]:bg-primary",
        orientation === "horizontal" && "h-px flex-1 mx-2",
        orientation === "vertical" && "ml-[18px] w-px min-h-4 self-stretch",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()

  if (step !== activeStep) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      className={cn("mt-2", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
}

