}: React.ComponentProps<"div"> & { step?: number }) {
  const { activeStep, orientation } = useStepper()

  const state =
    stepProp !== undefined && stepProp < activeStep ? "completed" : "upcoming"

  return (
    <div
      data-slot="stepper-separator"
      data-state={state}
      className={cn(
        "bg-border transition-colors data-[state=completed]:bg-primary",
        orientation === "horizontal" && "h-px flex-1 mx-2",
        orientation === "vertical" && "ml-[18px] w-px min-h-4 self-stretch",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()

  if (step !== activeStep) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      className={cn("mt-2", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
}

